def solve(download_url, file_type):
    if not isinstance(download_url, str) or not download_url.startswith("http"):
        raise ValueError("Invalid download URL")

    if file_type not in ["pdf", "png", "jpg"]:
        raise ValueError("Unsupported file type")

    # Core logic to download the file
    try:
        # Simulate download logic
        print(f"Downloading {file_type} from {download_url}")
        return True  # Simulate successful download
    except Exception as e:
        print(f"Download failed: {e}")
        return False
